import type { SyntaxNodeRef } from '@lezer/common';

import { convertJsonPath } from './json-path.js';
import { isDev } from '../../../../../../core/utils/is-node-environment.js';
import { preSpotErrorMark } from '../../../../decorations/decoration-marks.js';
import type { FilterFieldProps } from '../../../../FilterField.types.js';
import type { ConvertedLezerNode } from '../../../../types/conversion-utils.js';
import type { FilterFieldError } from '../../../../types/filter-field-error.js';
import type {
  FilterFieldErrorNode,
  FilterFieldJSONPathNode,
  FilterFieldKeyNode,
  FilterFieldLeafNode,
  FilterFieldLezerNodeType,
} from '../../../../types/tree-nodes.js';
import { getTextFromRange } from '../../../get-text.js';
import { convertNode } from '../generic-node.js';
import { updateNodeValues, convertToErrorNode } from '../node-mutations.js';
import { convertIdentifier } from '../value/identifier.js';

/**
 * Convert a filter field key node.
 * A key node may only an error node as direct child. In this case the converted node is undefined.
 * @internal
 */
export function convertFilterKey(
  node: SyntaxNodeRef,
  doc: string,
  parserConfig?: FilterFieldProps['parserConfig'],
): ConvertedLezerNode<FilterFieldKeyNode | undefined> {
  const { from, to } = node;
  const cursor = node.node.cursor();

  let convertedNode:
    | FilterFieldKeyNode
    | FilterFieldErrorNode
    | FilterFieldJSONPathNode = {
    type: 'Key',
    range: {
      from,
      to,
    },
    textValue: '',
    value: '',
  };
  const errors: FilterFieldError[] = [];

  let prevNode: FilterFieldLezerNodeType | undefined;

  cursor.iterate((childNode) => {
    const { from: childFrom, to: childTo } = childNode;
    const nodeName = childNode.name as FilterFieldLezerNodeType;

    switch (nodeName) {
      case 'FilterKey': {
        // Intentionally left empty.
        // Duplicating the tree cursor starts at the key node again.
        break;
      }
      case 'Identifier':
      case 'String':
      case 'IncompleteString':
      case 'Variable': {
        if (prevNode === 'JsonPathSquareOpeningBracket') {
          // skip the node as we already handled it in the JSONPath conversion
          break;
        }

        const {
          convertedNode: { textValue, value },
          isValid: isValidIdentifier,
          positionOperators: { endsWithOperator, startsWithOperator },
        } = convertIdentifier(childNode, doc, nodeName);

        updateNodeValues(convertedNode, textValue, value);

        if (
          !isValidIdentifier ||
          nodeName === 'IncompleteString' ||
          endsWithOperator ||
          startsWithOperator
        ) {
          convertToErrorNode(convertedNode);
          errors.push({ range: { from, to }, message: 'invalidKey' });
        }

        // Position operators are not supported for key nodes.
        if (endsWithOperator) {
          errors.push({
            range: endsWithOperator,
            message: 'unsupportedPositionOperator',
          });
        }
        if (startsWithOperator) {
          errors.push({
            range: startsWithOperator,
            message: 'unsupportedPositionOperator',
          });
        }

        break;
      }
      case 'InvalidIdentifier': {
        convertedNode = convertNode(childNode, doc)
          .convertedNode as FilterFieldErrorNode;
        errors.push({
          range: { from: childFrom, to: childTo },
          message: 'invalidKey',
        });
        break;
      }
      case 'PositionOperator':
      case 'InvalidPositionOperator': {
        const text = getTextFromRange(childNode, doc);
        updateNodeValues(convertedNode, text);
        convertToErrorNode(convertedNode);

        errors.push({
          range: { from: childFrom, to: childTo },
          message: 'unsupportedPositionOperator',
        });

        break;
      }
      case 'JsonPath': {
        const { convertedNode: jsonPathNode, errors: jsonPathErrors } =
          convertJsonPath(childNode, doc, parserConfig);
        convertedNode = jsonPathNode;
        errors.push(...jsonPathErrors);

        // skip the child nodes, as we already iterated through them (or want to ignore them if jsonPath is not supported)
        cursor.lastChild();
        break;
      }
      case '⚠':
        if (
          prevNode !== 'PositionOperator' &&
          prevNode !== 'InvalidPositionOperator'
        ) {
          if (prevNode !== 'Identifier') {
            errors.push({
              range: { from: childFrom, to: childTo + 1 },
              message: 'missingKeyError',
              decoration: preSpotErrorMark,
            });
          } else {
            const textValue = getTextFromRange(childNode, doc);
            if (textValue === ')' || textValue === ']') {
              updateNodeValues(convertedNode, textValue);
              convertToErrorNode(convertedNode);
              errors.push({
                range: { from: from, to: childTo },
                message: 'invalidKey',
              });
            }
          }
        }
        break;
      case 'JsonPathSquareOpeningBracket':
        // intentionally left empty as depending on how the filter is written,
        // it could occur here, but has already been handled in the JSONPath conversion.
        break;
      default:
        if (isDev()) {
          // eslint-disable-next-line no-console
          console.log(
            `${doc.toString()} | Syntax node '${
              childNode.name
            }' is not yet handled in the key conversion. Please make sure to handle all nodes accordingly.`,
          );
        }
    }

    prevNode = nodeName;
  });

  // Make sure the value matches the text value in case of an error.
  if ((convertedNode as FilterFieldLeafNode).type === 'Error') {
    convertedNode.value = convertedNode.textValue;
  }

  return {
    // For an empty error node, we return undefined.
    convertedNode: from === to ? undefined : convertedNode,
    errors,
  };
}
